// Recopilar todos los datos y preparar contexto para Claude
const kpis      = $('Query KPIs').first().json;
const top5      = $('Query Top 5').all().map(i => i.json);
const topAgent  = $('Query Agente Líder').first().json;
const daily     = $('Query Diario').all().map(i => i.json);
const trivias   = $('Query Trivias').all().map(i => i.json);

const now = new Date();
const fechaBogota = now.toLocaleString('es-CO', {timeZone:'America/Bogota', dateStyle:'full'});
const fechaCorta  = now.toLocaleDateString('es-CO', {timeZone:'America/Bogota', day:'numeric', month:'long'});
const fechaReporte= now.toLocaleString('es-CO', {timeZone:'America/Bogota'});

const tasaAcierto = kpis.total_respuestas > 0
  ? Math.round(kpis.correctas / kpis.total_respuestas * 100) + '%'
  : '0%';
const tasaPart = kpis.total_usuarios > 0
  ? (kpis.activos / kpis.total_usuarios * 100).toFixed(2) + '%'
  : '0%';

// Proyección simple
let proyeccion = null;
if (daily.length >= 2) {
  const n = daily.length;
  const pts = daily.map((d, i) => ({x: i+1, y: daily.slice(0,i+1).reduce((s,r)=>s+parseInt(r.respuestas),0)}));
  const sx = pts.reduce((s,p)=>s+p.x,0), sy = pts.reduce((s,p)=>s+p.y,0);
  const sxy = pts.reduce((s,p)=>s+p.x*p.y,0), sx2 = pts.reduce((s,p)=>s+p.x*p.x,0);
  const slope = (n*sxy-sx*sy)/(n*sx2-sx*sx);
  const intercept = (sy-slope*sx)/n;
  const pred37 = Math.round(slope*37+intercept);
  const residuals = pts.map((p,i)=>p.y-(slope*(i+1)+intercept));
  const se = Math.sqrt(residuals.reduce((s,r)=>s+r*r,0)/Math.max(n-2,1));
  const r2 = 1 - residuals.reduce((s,r)=>s+r*r,0)/pts.reduce((s,p)=>{const m=sy/n;return s+(p.y-m)**2;},0);
  proyeccion = {slope: slope.toFixed(1), r2: (r2*100).toFixed(0), se: se.toFixed(0), pred37, n};
}

// Contexto para Claude
const contexto = `
Datos del reporte diario Crack Tesos 2026 — ${fechaBogota}

KPIs generales:
- Total participantes activos: ${kpis.total_usuarios}
- Registrados: ${kpis.registrados}
- Han participado: ${kpis.activos}
- Respuestas totales: ${kpis.total_respuestas}
- Correctas: ${kpis.correctas} | Incorrectas: ${kpis.incorrectas}
- Tasa de acierto: ${tasaAcierto}
- Tasa de participación: ${tasaPart}
- Goles acumulados totales: ${kpis.goles_totales}
- Trivias activas: ${kpis.trivias_activas}

Top 5 ranking:
${top5.map((p,i)=>`${i+1}. ${p.name} (${p.agent_name}) — ${p.total_goals} goles, ${p.correct_count} correctas, ${p.vel_min} min prom`).join('\n')}

Agente líder: ${topAgent.agent_name} — ${topAgent.participantes} participantes, ${topAgent.goles} goles, ${topAgent.pct_acierto}% acierto

Trivias enviadas:
${trivias.map(t=>`Trivia #${t.trivia_number}: ${t.respuestas} respuestas, ${t.correctas} correctas`).join('\n')}

Participación diaria:
${daily.map(d=>`${d.dia}: ${d.respuestas} respuestas (${d.correctas} correctas)`).join('\n')}

${proyeccion ? `Proyección (regresión lineal, n=${proyeccion.n} días): pendiente=${proyeccion.slope} resp/día, R²=${proyeccion.r2}%, SE=${proyeccion.se}, proyección día 37: ${proyeccion.pred37} respuestas acumuladas` : 'Proyección: insuficientes datos (se necesitan ≥2 días)'}
`;

return [{json: {
  kpis, top5, topAgent, daily, trivias, proyeccion,
  fechaReporte, fechaCorta, fechaBogota,
  tasaAcierto, tasaPart,
  contexto
}}];

